208	        if (const auto env_nvcc_path = get_env<std::string>("EP_JIT_NVCC_COMPILER"); not env_nvcc_path.empty())
209	            nvcc_path = env_nvcc_path;
210	        const auto [nvcc_major, nvcc_minor] = get_nvcc_version();
