212	
213	        // The override the compiler flags
214	        // Only NVCC >= 12.9 supports arch-specific family suffix
215	        const auto arch = device_runtime->get_arch(false, nvcc_major > 12 or nvcc_minor >= 9);
216	        flags = fmt::format("{} -I{} --gpu-architecture=sm_{} "
217	                            "--compiler-options=-fPIC,-O3,-fconcepts,-Wno-deprecated-declarations,-Wno-abi "
