233	            compile_dir.c_str(), nvcc_path.c_str(), code_path.c_str(), cubin_path.c_str(), flags);
234	        if (get_env("EP_JIT_DEBUG", 0) or get_env("EP_JIT_PRINT_COMPILER_COMMAND", 0))
235	            printf("Running NVCC command: %s\n", command.c_str());
236	        const auto [return_code, output] = call_external_command(command);
237	        if (return_code != 0) {
238	            printf("NVCC compilation failed: %s\n", output.c_str());
239	            EP_HOST_ASSERT(false and "NVCC compilation failed");
240	        }
241	
242	        // Compile to PTX if needed
243	        if (ptx_path.has_value()) {
244	            const auto ptx_command = fmt::format("cd {} && {} {} -ptx -o {} {}",
245	                compile_dir.c_str(), nvcc_path.c_str(), code_path.c_str(), ptx_path->c_str(), flags);
246	            if (get_env("EP_JIT_DEBUG", 0) or get_env("EP_JIT_PRINT_COMPILER_COMMAND", 0))
247	                printf("Running NVCC PTX command: %s\n", ptx_command.c_str());
248	            const auto [ptx_return_code, ptx_output] = call_external_command(ptx_command);
249	            if (ptx_return_code != 0) {
250	                printf("NVCC PTX compilation failed: %s\n", ptx_output.c_str());
251	                EP_HOST_ASSERT(false and "NVCC PTX compilation failed");
252	            }
253	        }
254	
255	        // Check local memory usage
256	        if (get_env("EP_JIT_PTXAS_CHECK", 0))
257	            EP_HOST_ASSERT(not std::regex_search(output, std::regex(R"(Local memory used)")));
258	
259	        // Print PTXAS log
260	        if (get_env("EP_JIT_DEBUG", 0) or get_env("EP_JIT_PTXAS_VERBOSE", 0))
261	            printf("%s", output.c_str());
262	    }
