20	
21	static KernelHandle load_kernel(const std::filesystem::path& cubin_path, const std::string& func_name,
22	                                LibraryHandle *library_opt = nullptr) {
23	    LibraryHandle library;
24	    KernelHandle kernel{};
25	    CUDA_RUNTIME_CHECK(cudaLibraryLoadFromFile(&library, cubin_path.c_str(), nullptr, nullptr, 0, nullptr, nullptr, 0));
26	    nvshmemx_culibrary_init(library);
27	    CUDA_RUNTIME_CHECK(cudaLibraryGetKernel(&kernel, library, func_name.c_str()));
28	
29	    if (library_opt != nullptr)
30	        *library_opt = library;
31	    return kernel;
32	}
