34	static void unload_library(const LibraryHandle& library) {
35	    nvshmemx_culibrary_finalize(library);
36	    const auto error = cudaLibraryUnload(library);
37	    EP_HOST_ASSERT(error == cudaSuccess or error == cudaErrorCudartUnloading);
38	}
39	
40	static LaunchConfigHandle construct_launch_config(const KernelHandle& kernel,
41	                                                  const cudaStream_t& stream, const int& smem_size,
42	                                                  const dim3& grid_dim, const dim3& block_dim, const int& cluster_dim) {
43	    if (smem_size > 0)
44	        CUDA_RUNTIME_CHECK(cudaFuncSetAttribute(kernel, cudaFuncAttributeMaxDynamicSharedMemorySize, smem_size));
45	
46	    LaunchConfigHandle config;
47	    config.gridDim = grid_dim;
48	    config.blockDim = block_dim;
49	    config.dynamicSmemBytes = smem_size;
50	    config.stream = stream;
51	    config.numAttrs = 0;
